export default function App() {
  const [step, setStep] = React.useState(0);
  const [direction, setDirection] = React.useState('next');
  const current = phases[step];
  const progress = ((step + 1) / phases.length) * 100;

  function next() {
    if (step < phases.length - 1) {
      setDirection('next');
      setStep(step + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      setDirection('back');
      setStep(0);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }

  function back() {
    if (step > 0) {
      setDirection('back');
      setStep(step - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }

  return (
    <main className="app">
      <div className="bgBlob blob1"></div>
      <div className="bgBlob blob2"></div>
      <div className="float f1">🐾</div>
      <div className="float f2">🎈</div>
      <div className="float f3">💛</div>
      <div className="float f4">✨</div>

      <section className="phoneCard">
        <div className="progressTrack">
          <div className="progressFill" style={{ width: `${progress}%` }} />
        </div>

        <div className="imageWrap">
          <img src={current.image} alt={current.title} className={current.final ? 'heroImage finalImage' : 'heroImage'} />
          <div className="imageOverlay"></div>
          <div className="screenBadge">{step + 1} / {phases.length}</div>
        </div>

        <div className={`contentCard ${direction}`} key={step}>
          <p className="kicker">{current.kicker}</p>
          <h1>{current.title}</h1>

          <div className="message">
            {current.text.split('\n').map((line, index) => (
              line.trim() === '' ? <br key={index} /> : <p key={index}>{line}</p>
            ))}
          </div>

          <div className="buttons">
            <button className="backBtn" onClick={back} disabled={step === 0}>
              ←
            </button>
            <button className={current.final ? 'mainBtn finalBtn' : 'mainBtn'} onClick={next}>
              {current.button}
            </button>
          </div>

          <div className="dots">
            {phases.map((_, i) => (
              <span key={i} className={i === step ? 'dot active' : 'dot'}></span>
            ))}
          </div>
        </div>
      </section>
    </main>
  );
}
